var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"윽! 모래 폭풍이 다시 거세지고 있어요!","JPN":"うっ！　砂嵐がまた強くなってます！","ENG":"Ngh! The sandstorm is getting stronger again!","TWN":"唔！沙塵暴又變得更猛烈了！"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아닐라. 저 안에 있는 동안 훈련을 게을리하지는 않았나?","JPN":"アニラ。あの中にいる間に、訓練を怠っていたわけではないだろうな。","ENG":"Anila. Have you neglected your training inside that thing?","TWN":"雅妮拉，你在這裡的時候沒有偷懶忘記訓練吧？"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그럴리가요. 누가 가르쳤는데.","JPN":"そんな。誰に教わったと思っているんですか？","ENG":"Of course, not. Did you forget who trained me?","TWN":"怎麼可能，也不看看是誰教我的。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"확인해보시겠어요?","JPN":"確かめてみます？","ENG":"Or do you want to see for yourself?","TWN":"要來確認一下嗎？"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"폭풍이…… 사라졌어?","JPN":"嵐が……消えた？","ENG":"The storm... disappeared?","TWN":"沙塵暴……消失了？"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"이번에야말로 반드시 마무리 짓겠습니다.","JPN":"今度こそ必ず終わらせます。","ENG":"I will make sure to end it this time.","TWN":"這次一定能結束這一切的。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"하지만 놈을 붙잡기 위해선 차원 닻이 필요해요. 차원 닻을 시동할 시간을 벌어야 합니다.","JPN":"ですが、やつを捕まえるためには次元錨が必要です。次元錨を始動する時間を稼がなければいけません。","ENG":"But in order to catch it, we need the Dimension Anchor and enough time to get it started.","TWN":"但是要抓住它，必須使用次元錨。現在要爭取啟動次元錨的時間。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"시간을 끌 녀석들은 충분하지.","JPN":"時間を稼いでくれるやつらなら十分だ。","ENG":"We have enough people who will buy us some time.","TWN":"有人可以幫我們爭取足夠的時間。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"반드시 날 도와주기로 약속했거든.","JPN":"必ず私に協力すると約束したからな。","ENG":"They promised to come help.","TWN":"他們答應過一定會幫我的。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"바루나스트라를 향해 포격이?","JPN":"ヴァルナストラに向かって砲撃が？","ENG":"A bombardment toward Varunastra?","TWN":"是誰在向那個鯨魚開炮？"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"Could it be...?","TWN":"難道說……？"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"모래 폭풍이 걷힌 걸 확인하고 곧장 달려왔다. 늦지 않았군.","JPN":"砂嵐が治まったところを確認してすぐに駆けつけてきた。間に合ったな。","ENG":"We came as soon as we saw that the sandstorm had cleared. I'm glad we made it in time.","TWN":"沙塵暴結束後，我們就立刻趕過來，幸好還不晚。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"저 침식체 새끼를 갉아 먹으러 돌아왔다고! 그렇지, 마리?","JPN":"あの侵食体の野郎を倒すために戻ってきたんだ！　そうだろう？　マリー！","ENG":"We're back to rip that C.O. a new one! Isn't that right, Marie?","TWN":"我們是回來啃食那個侵蝕體的！對吧，瑪麗？"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"적 개체 포착했습니다. 침식파 측정 결과…… 오류?","JPN":"敵個体を捕らえました。侵食波測定の結果……エラー？","ENG":"Enemy entity detected. The Corruption ray measurement results are– An error?","TWN":"發現敵人，侵蝕波測量結果……出錯？"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"게다가 차원 계면이 융해되기 시작했어요. 이대로라면 침식체가 도주합니다.","JPN":"さらに次元界面が融解し始めました。このままだと侵食体が逃走します。","ENG":"What's worse is that the dimension surface has started to melt. The C.O. will escape at this rate.","TWN":"次元邊界已經開始瓦解，再這樣下去，侵蝕體會逃走的。"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"역시 파티마씨를 불러오는 게…….","JPN":"やはりファティマさんをお呼びした方が……","ENG":"I knew we should've called Fatima for help...","TWN":"果然還是要找法蒂瑪來……"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"그럴 필요 없어 아가씨. 저 여자의 실력은 내가 장담하지.","JPN":"その必要はない、お嬢さん。あの女の実力は俺が保証する。","ENG":"No need for that. I can vouch for what that woman can do.","TWN":"不需要，那個女人的實力我可以作證。"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L33_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"우리는 그냥 멀리서 엄호만 해주면 된 단 말씀!","JPN":"俺たちはただ遠くから援護するだけでいいってこった！","ENG":"All we need to do is provide cover from afar!","TWN":"我們只需要在遠處掩護她就好！"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"마리도 몸이 근질근질해서 포신 움직이는 것 좀 봐~","JPN":"マリもムズムズして砲身が動いてるぜ～","ENG":"Look at how restless Marie is with her gun barrel twitching!","TWN":"瑪麗等不及要大展身手囉，看看她舞動炮管的樣子～"},"stage":{"bg":"PROLOGUE_02","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아샤! 저와 함께 차원 닻을 시동해야 해요.","JPN":"アーシャ！　私と一緒に次元錨に始動をかけるのです。","ENG":"Asha! You need to start the Dimension Anchor with me!","TWN":"阿莎！你來和我一起啟動次元錨。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네? 하, 하지만 저희 둘 다 무슨 코드가 맞지 않는다고…….","JPN":"えっ？　で、でも、私たち二人ともコードが合わないって……","ENG":"What? B-but isn't it said that our code doesn't match...?","TWN":"可是？等一下，不是說需要啟動代碼……"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"분명 부전대장님은 방법을 마련했을 겁니다.","JPN":"副戦隊長ならきっと、何かしらの方法を考えておいたはずです。","ENG":"I'm sure Deputy Commander left us with a way to start it.","TWN":"副戰隊長一定有先想好辦法。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그리고 그건 아마 당신과 함께하지 않으면 해낼 수 없을 거예요.","JPN":"そしてそれはおそらくあなたと一緒でないとできないでしょう。","ENG":"And I probably can't do it without you.","TWN":"而且那可能只有和你一起才能完成。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…… 네. 알겠어요.","JPN":"……はい。わかりました。","ENG":"...Okay.","TWN":"……好，我跟你去。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지가 남겨준 기회를 절대 헛되게 하지 않을게요.","JPN":"お父さんが残してくれたチャンスを絶対に無駄にはしません。","ENG":"I won't let this opportunity my father gave us go to waste.","TWN":"我不會辜負爸爸留下的機會的。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>생체 식별 코드 유사도 확인. 추가 인증을 요구합니다.</color>","JPN":"<color=#ffd34c>生体識別コードの類似度を確認。追加認証を要請します。</color>","ENG":"<color=#ffd34c>Biometric authentication similarity confirmed. Requesting additional authentication.</color>","TWN":"<color=#ffd34c>正在匹配生物識別代碼。需要額外認證。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L49_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"역시, 방법을 만들어 두셨어.","JPN":"やっぱり方法があったんだ。","ENG":"I knew it. He did leave us a chance.","TWN":"我就知道，他早有預備。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"추가…… 인증?","JPN":"追加……認証？","ENG":"Additional... authentication?","TWN":"額外……認證？"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아빠가 아샤에게 남긴, 사랑한다는 증거.</color>","JPN":"<color=#ffd34c>お父さんがアーシャに残した、愛しているという証拠。</color>","ENG":"<color=#ffd34c>Proof that your dad loves you, Asha.</color>","TWN":"<color=#ffd34c>爸爸留給阿莎的，愛的證明。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>힌트: 넌 혼자가 아니야.</color>","JPN":"<color=#ffd34c>ヒント：お前は一人ではない。</color>","ENG":"<color=#ffd34c>Here's a hint. \\"You're not alone.\\"</color>","TWN":"<color=#ffd34c>提示：你並不孤單。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"사랑한다는…… 증거.","JPN":"愛しているっていう……証拠。","ENG":"Proof that... he loves me.","TWN":"愛我的……證明。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"내가 혼자가 아니라 증명해주는 건…… 바로 이 나침반이야.","JPN":"私が一人じゃないって証明してくれるのは……この羅針盤だ。","ENG":"What he left that proves that I'm not alone... is this compass.","TWN":"證明我並不孤單的……就是這個指南針吧。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이걸 여기에 꽂으면…….","JPN":"これをここに挟むと……","ENG":"If I place it here...","TWN":"把這個插在這裡……"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_07"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아티팩트 확인. 추가 메시지를 재생합니다.</color>","JPN":"<color=#ffd34c>アーティファクト確認。追加メッセージを再生します。</color>","ENG":"<color=#ffd34c>Artifact confirmed. Playing additional messages.</color>","TWN":"<color=#ffd34c>人造神器已確認。播放語音訊息。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"<color=#ffd34c>이걸 들을 때면, 아닐라와 만난 거겠지? 전대장은 무사하고?</color>","JPN":"<color=#ffd34c>これを聞いているということは、アニラと出会ったのだろう？　戦隊長は無事か？</color>","ENG":"<color=#ffd34c>If you hear this, then you must have met Anila, right? Is Commander safe as well?</color>","TWN":"<color=#ffd34c>當你聽到這段訊息，就表示你已經見到雅妮拉了吧？戰隊長都好嗎？</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"<color=#ffd34c>못난 아빠가 이렇게밖에 할 수 없는 점. 미안하구나.</color>","JPN":"<color=#ffd34c>こんなことしかできないダメな父親ですまない。</color>","ENG":"<color=#ffd34c>I'm sorry that this is all that I can do for you as your father.</color>","TWN":"<color=#ffd34c>爸爸沒用，只能用這種方式，對不起。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"<color=#ffd34c>아샤. 네가 들고 있는 나침반은 아빠에게 있어서 소중한 물건이야.</color>","JPN":"<color=#ffd34c>アーシャ。お前が持っている羅針盤はお父さんにとって大事なものだ。</color>","ENG":"<color=#ffd34c>Asha. That compass of yours is something precious to your old man.</color>","TWN":"<color=#ffd34c>阿莎。你手中的指南針對爸爸來說是非常珍貴的東西。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"<color=#ffd34c>어둠 속에서도 혼자가 아니라는 사실을 깨닫게 해줬거든.</color>","JPN":"<color=#ffd34c>闇の中でも一人ではないということを知らせてくれたんだ。</color>","ENG":"<color=#ffd34c>It made me realize that I wasn't alone even in the dark.</color>","TWN":"<color=#ffd34c>在黑暗中能讓我意識到自己並不孤單。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"<color=#ffd34c>네가 문득 혼자라는 생각이 들 때면, 그 나침반을 바라보거라.</color>","JPN":"<color=#ffd34c>お前が孤独だと思う時は、その羅針盤を見てみなさい。</color>","ENG":"<color=#ffd34c>Whenever you feel that you're alone, look at the compass.</color>","TWN":"<color=#ffd34c>當你覺得孤單時，就看看那個指南針吧。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"<color=#ffd34c>인도하는 태양은 늘 그렇듯, 우릴 향해 손을 내밀어줄 테니.</color>","JPN":"<color=#ffd34c>導く太陽はいつものように、俺たちに手を差し伸べてくれるはずだ。</color>","ENG":"<color=#ffd34c>Because, as always, the guiding sun will reach out toward us.</color>","TWN":"<color=#ffd34c>因為引導我們的太陽，總是會向我們伸出援手。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"<color=#ffd34c>사랑한다. 내 딸.</color>","JPN":"<color=#ffd34c>愛しているぞ。アーシャ。</color>","ENG":"<color=#ffd34c>I love you, Asha.</color>","TWN":"<color=#ffd34c>爸爸愛你，我的女兒。</color>"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"정말 못됐다니까. 그렇게 고생을 했는데…… ","JPN":"本当にズルい。あんなに苦労したくせに…… ","ENG":"You really are a terrible father. After all that you've been through...","TWN":"爸爸好壞，自己明明那麼辛苦……"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"끝까지 자기 걱정은 안 하면 어떡해요.","JPN":"最後まで自分のことは二の次だなんて。","ENG":"How can you not worry about yourself until the end?","TWN":"怎麼能連自己的安危都不顧呢……？"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국 고유 무장. <color=#ffd34c>차원 닻</color> 시동.","JPN":"管理局固有武装。<color=#ffd34c>次元錨</color>始動。","ENG":"Activating Administration Unique Gear: <color=#ffd34c>Dimension Anchor</color>.","TWN":"管理局專屬武裝。<color=#ffd34c>次元錨</color>啟動。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_04"},{"id":"L26_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지의 의지를 이어서…… 끝을 내주세요.","JPN":"お父さんの意志を受け継いで……終わらせてください。","ENG":"Following my father's will... please put an end to this.","TWN":"繼承我爸爸的意志……請結束這一切吧。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"부전대장님도 분명 기뻐하실 겁니다. 고생하셨어요.","JPN":"副戦隊長もきっと喜ぶでしょう。後は任せてください。","ENG":"Deputy Commander would be so proud. Great work.","TWN":"副戰隊長也一定會很高興的，辛苦了。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"차원 닻 시동! 나가파샤 활성화! 좌표 고정 실시!","JPN":"次元錨始動！　ナーガパーシャ活性化！　座標固定実施！","ENG":"Activating Dimension Anchor! Activating Nagapasha! Locking coordinates!","TWN":"次元錨啟動！那伽羂索啟動！開始鎖定座標！"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"차, 차원 계면 융해 중단…… 불안정하던 좌표가 고정되었습니다.","JPN":"じ、次元界面融解中断……不安定だった座標が固定されました。","ENG":"Th-the dimension surface stopped melting...The unstable coordinates have been fixed.","TWN":"次，次元介面沒有再繼續瓦解……座標已被鎖定。"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"전투 개시! 온 화력을 목표에 집중합니다!","JPN":"戦闘開始！　すべての火力を標的に向けます！","ENG":"Commence attack! Focus all firepower on the target!","TWN":"全體開火！將所有火力集中到目標身上！"},"stage":{"bg":"CITY_DESERT","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};